using UnityEngine;
using Climbing;
using UnityEditor;
using System.Linq;

public class PrefabClimbFixer
{
    public static string Fix()
    {
        string prefabPath = "Assets/Dynamic Parkour System/Prefabs/Player.prefab";
        GameObject prefab = AssetDatabase.LoadAssetAtPath<GameObject>(prefabPath);
        if (prefab == null) return "Player prefab not found at " + prefabPath;

        ClimbController cc = prefab.GetComponentInChildren<ClimbController>();
        if (cc == null) return "ClimbController not found in prefab or its children.";

        SerializedObject so = new SerializedObject(cc);
        so.FindProperty("AutoSearchBones").boolValue = true;

        Animator anim = prefab.GetComponentInChildren<Animator>();
        if (anim != null && anim.avatar != null && anim.avatar.isHuman)
        {
            // We can't use GetBoneTransform on a non-instantiated prefab easily,
            // but we can look through children for names typically used in rigs.
            Transform[] allChildren = prefab.GetComponentsInChildren<Transform>(true);

            if (so.FindProperty("LHand").objectReferenceValue == null)
                so.FindProperty("LHand").objectReferenceValue = allChildren.FirstOrDefault(t => t.name.ToLower().Contains("lefthand") || t.name.EndsWith("Hand_L") || t.name.Contains("LeftHand"))?.gameObject;

            if (so.FindProperty("RHand").objectReferenceValue == null)
                so.FindProperty("RHand").objectReferenceValue = allChildren.FirstOrDefault(t => t.name.ToLower().Contains("righthand") || t.name.EndsWith("Hand_R") || t.name.Contains("RightHand"))?.gameObject;

            if (so.FindProperty("LFoot").objectReferenceValue == null)
                so.FindProperty("LFoot").objectReferenceValue = allChildren.FirstOrDefault(t => t.name.ToLower().Contains("leftfoot") || t.name.EndsWith("Foot_L") || t.name.Contains("LeftFoot"))?.gameObject;

            if (so.FindProperty("RFoot").objectReferenceValue == null)
                so.FindProperty("RFoot").objectReferenceValue = allChildren.FirstOrDefault(t => t.name.ToLower().Contains("rightfoot") || t.name.EndsWith("Foot_R") || t.name.Contains("RightFoot"))?.gameObject;
        }

        so.ApplyModifiedProperties();
        EditorUtility.SetDirty(cc);
        AssetDatabase.SaveAssets();

        return "Successfully updated Player PREFAB ClimbController settings.";
    }
}
